<script setup lang="ts">
import { computed,onMounted,reactive,ref } from 'vue';import{useRoute,useRouter}from'vue-router';import Button from'primevue/button';import Dialog from'primevue/dialog';import MainLayout from'../layouts/MainLayout.vue'
import{createTransportCommand,deleteTransportCommand,fetchTransportCommands,fetchTransportManufacturers,fetchTransportManufacturerVehicleTypes,updateTransportCommand}from'../api/transportApi';import type{TransportCommand,TransportManufacturer,TransportManufacturerVehicleType}from'../types/transport'
const route=useRoute(),router=useRouter(),manufacturerId=String(route.params.manufacturerId),typeId=String(route.params.typeId);const manufacturers=ref<TransportManufacturer[]>([]),types=ref<TransportManufacturerVehicleType[]>([]),items=ref<TransportCommand[]>([]),dialogVisible=ref(false),saving=ref(false),editingId=ref<string|null>(null),error=ref<string|null>(null);const form=reactive({commandCode:'',commandName:'',processType:'MOVE',description:'',sortOrder:null as number|null,isActive:true});const processTypes=['MOVE','LOADING','UNLOADING','WAIT','STATUS','TASK_CONTROL','OTHER'];const manufacturer=computed(()=>manufacturers.value.find(x=>x.manufacturerId===manufacturerId));const vehicleType=computed(()=>types.value.find(x=>x.manufacturerVehicleTypeId===typeId));const msg=(e:unknown,f:string)=>e instanceof Error?e.message:f
async function load(){try{[manufacturers.value,types.value,items.value]=await Promise.all([fetchTransportManufacturers(),fetchTransportManufacturerVehicleTypes(true),fetchTransportCommands(typeId,true)])}catch(e){error.value=msg(e,'コマンドの取得に失敗しました。')}}function open(item?:TransportCommand){editingId.value=item?.commandId??null;Object.assign(form,{commandCode:item?.commandCode??'',commandName:item?.commandName??'',processType:item?.processType??'MOVE',description:item?.description??'',sortOrder:item?.sortOrder??null,isActive:item?.isActive??true});error.value=null;dialogVisible.value=true}async function save(){if(!form.commandCode.trim()||!form.commandName.trim()){error.value='コードとコマンド名は必須です。';return}saving.value=true;try{const request={...form,commandCode:form.commandCode.trim(),commandName:form.commandName.trim(),description:form.description.trim()||null};editingId.value?await updateTransportCommand(editingId.value,request):await createTransportCommand(typeId,request);dialogVisible.value=false;await load()}catch(e){error.value=msg(e,'コマンドの保存に失敗しました。')}finally{saving.value=false}}async function remove(item:TransportCommand){if(!confirm(`コマンド「${item.commandName}」を削除しますか？`))return;try{await deleteTransportCommand(item.commandId);await load()}catch(e){error.value=msg(e,'削除に失敗しました。')}}onMounted(load)
</script>
<template><MainLayout><section class="page master-page"><div class="breadcrumbs"><RouterLink :to="{name:'transport-manufacturers'}">メーカー一覧</RouterLink><span>›</span><RouterLink :to="{name:'transport-vehicle-types',params:{manufacturerId}}">{{ manufacturer?.name??'メーカー' }}</RouterLink><span>›</span><strong>{{ vehicleType?.vehicleType??'種別' }}</strong></div><header class="card page-header"><div><Button label="AGF・AGV一覧へ戻る" icon="pi pi-arrow-left" text @click="router.push({name:'transport-vehicle-types',params:{manufacturerId}})"/><h1>{{ manufacturer?.name }} / {{ vehicleType?.vehicleType }} コマンド一覧</h1><p>このメーカー・種別で利用できるコマンドを管理します。</p></div><Button label="コマンドを追加" icon="pi pi-plus" @click="open()"/></header><p v-if="error" class="error">{{ error }}</p><section class="card list-card"><div class="list-header"><strong>登録コマンド</strong><span>{{ items.length }}件</span></div><p v-if="!items.length" class="empty">コマンドがありません。</p><article v-for="item in items" :key="item.commandId" class="command-row"><code>{{ item.commandCode }}</code><span class="row-main"><strong>{{ item.commandName }}</strong><small>{{ item.processType }}<template v-if="item.description">・{{ item.description }}</template></small></span><span class="status" :class="{inactive:!item.isActive}">{{ item.isActive?'有効':'無効' }}</span><span class="actions"><Button label="編集" icon="pi pi-pencil" text @click="open(item)"/><Button label="削除" icon="pi pi-trash" text severity="danger" @click="remove(item)"/></span></article></section><Dialog v-model:visible="dialogVisible" modal :header="editingId?'コマンドを編集':'コマンドを追加'" :style="{width:'min(560px,92vw)'}"><div class="context">{{ manufacturer?.name }} / {{ vehicleType?.vehicleType }}</div><div class="form"><label>コマンドコード<input v-model="form.commandCode"/></label><label>コマンド名<input v-model="form.commandName"/></label><label>処理種別<select v-model="form.processType"><option v-for="x in processTypes" :key="x">{{ x }}</option></select></label><label>説明<textarea v-model="form.description" rows="4"/></label><label>表示順<input v-model.number="form.sortOrder" type="number"/></label><label class="check"><input v-model="form.isActive" type="checkbox"/>有効にする</label><p v-if="error" class="error">{{ error }}</p></div><template #footer><Button label="キャンセル" text severity="secondary" @click="dialogVisible=false"/><Button label="保存" :loading="saving" @click="save"/></template></Dialog></section></MainLayout></template>
<style scoped src="./transport-master-page.css"></style>
